from flask import Flask, request, jsonify
from selenium import webdriver
from selenium.webdriver.chrome.service import Service as ChromeService
from selenium.webdriver.common.by import By
from selenium.webdriver.chrome.options import Options
import boto3
import os

app = Flask(__name__)

# AWS S3 configuration
s3_client = boto3.client('s3')
bucket_name = 'your-s3-bucket-name'

# Set up headless Chrome
chrome_options = Options()
chrome_options.add_argument("--headless")
chrome_options.add_argument("--disable-gpu")
chrome_options.add_argument("--window-size=1280x720")

service = ChromeService(executable_path='/path/to/chromedriver')
driver = webdriver.Chrome(service=service, options=chrome_options)

@app.route('/screenshot', methods=['POST'])
def screenshot():
    url = request.json.get('url')
    if not url:
        return jsonify({'error': 'URL is required'}), 400

    try:
        driver.get(url)
        
        # Generate screenshot
        screenshot_path = f'/tmp/{os.path.basename(url)}.png'
        driver.save_screenshot(screenshot_path)

        # Upload to S3
        s3_client.upload_file(screenshot_path, bucket_name, os.path.basename(screenshot_path))
        
        return jsonify({'message': 'Screenshot generated and uploaded', 'url': f'https://{bucket_name}.s3.amazonaws.com/{os.path.basename(screenshot_path)}'}), 200

    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=80)